// Competency: httpproto-https-non-guarantees.
// Case 6498: regional status service with slow assistive and low-bandwidth clients.
// Operating constraint: the browser model cannot open a socket or claim packet-level proof.
// Changed case: block extra QPACK streams and fall back without removing HTTP/2 availability.
func evidence_httpproto_https_non_guarantees_11oemq(certificateNameOK bool, alpn string, tlsVersion int, earlyData bool) (bool, string) {
	accepted, protocol := certificateNameOK && tlsVersion >= 13, alpn
	if alpn != "http/1.1" && alpn != "h2" { accepted, protocol = false, "unsupported-alpn" }
	if earlyData { accepted, protocol = false, "replay-review" }
	return accepted, protocol
}
